assistantMessages:
I'll check your wallet balance using the MetaMask agent wallet skill.

```typescript
import { chromium } from 'playwright';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

// Configuration
const PROFILE_PATH = path.join(os.homedir(), '.agent-wallet', 'chrome-profile');
const LOG_PATH = path.join(os.homedir(), '.agent-wallet', 'logs');
const METAMASK_EXTENSION_ID = 'nkbihfbeogaeaoehlefnkodbefgpgknn';

async function getWalletBalance() {
  console.log('🦊 Starting MetaMask Agent Wallet...');
  console.log(`📁 Profile path: ${PROFILE_PATH}`);

  // Check if profile exists
  if (!fs.existsSync(PROFILE_PATH)) {
    console.error('❌ Agent wallet profile not found.');
    console.error('   Run: npm run setup');
    process.exit(1);
  }

  // Ensure log directory exists
  if (!fs.existsSync(LOG_PATH)) {
    fs.mkdirSync(LOG_PATH, { recursive: true });
  }

  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
    headless: false, // MetaMask requires headed mode
    args: [
      `--disable-extensions-except=${PROFILE_PATH}/extensions/metamask`,
      `--load-extension=${PROFILE_PATH}/extensions/metamask`,
      '--no-sandbox',
      '--disable-setuid-sandbox',
    ],
    viewport: { width: 1280, height: 720 },
  });

  try {
    // Open MetaMask popup
    console.log('\n📊 Opening MetaMask to check balances...');
    const page = await browser.newPage();

    // Navigate to MetaMask popup
    await page.goto(`chrome-extension://${METAMASK_EXTENSION_ID}/home.html`);
    await page.waitForLoadState('networkidle');
    await page.waitForTimeout(2000);

    // Check if MetaMask is unlocked
    const isLocked = await page.locator('[data-testid="unlock-page"]').isVisible()
      .catch(() => false);

    if (isLocked) {
      console.log('🔒 MetaMask is locked. Please unlock it first.');
      console.log('   The browser window is open - enter your password to unlock.');

      // Wait for unlock (up to 60 seconds)
      await page.waitForSelector('[data-testid="account-menu-icon"]', { 
        timeout: 60000 
      });
      console.log('✅ MetaMask unlocked!');
    }

    // Wait for main UI to load
    await page.waitForSelector('[data-testid="account-menu-icon"]', { timeout: 15000 });
    await page.waitForTimeout(1000);

    // Get account address
    let address = 'Unknown';
    try {
      // Click on account name to copy address
      const accountButton = page.locator('[data-testid="account-menu-icon"]');
      await accountButton.click();
      await page.waitForTimeout(500);

      // Get address from account details
      const addressEl = page.locator('[data-testid="account-list-address"]').first();
      if (await addressEl.isVisible()) {
        address = await addressEl.textContent() || 'Unknown';
        address = address.trim();
      }

      // Close menu
      await page.keyboard.press('Escape');
      await page.waitForTimeout(500);
    } catch (e) {
      console.log('   (Could not retrieve address)');
    }

    // Get ETH balance from main screen
    let ethBalance = 'Unknown';
    let ethUsdValue = 'Unknown';

    try {
      // Main balance display
      const balanceEl = page.locator('[data-testid="eth-overview__primary-currency"]');
      if (await balanceEl.isVisible({ timeout: 5000 })) {
        ethBalance = await balanceEl.textContent() || 'Unknown';
        ethBalance = ethBalance.trim();
      }

      // USD value
      const usdEl = page.locator('[data-testid="eth-overview__secondary-currency"]');
      if (await usdEl.isVisible({ timeout: 3000 })) {
        ethUsdValue = await usdEl.textContent() || 'Unknown';
        ethUsdValue = ethUsdValue.trim();
      }
    } catch (e) {
      // Try alternative selectors
      try {
        const balanceEl = page.locator('.currency-display-component__text').first();
        ethBalance = await balanceEl.textContent() || 'Unknown';
      } catch (e2) {
        console.log('   (Could not retrieve ETH balance from UI)');
      }
    }

    // Get token balances by navigating to tokens tab
    const tokenBalances: Array<{ name: string; balance: string; usdValue: string }> = [];

    try {
      // Click on "Tokens" tab
      const tokensTab = page.locator('[data-testid="account-overview__asset-tab"]');
      if (await tokensTab.isVisible({ timeout: 3000 })) {
        await tokensTab.click();
        await page.waitForTimeout(1500);

        // Get token list items
        const tokenItems = page.locator('[data-testid="multichain-token-list-item"]');
        const tokenCount = await tokenItems.count();

        for (let i = 0; i < Math.min(tokenCount, 10); i++) {
          try {
            const item = tokenItems.nth(i);
            const nameEl = item.locator('[data-testid="multichain-token-list-item-token-name"]');
            const balanceEl = item.locator('[data-testid="multichain-token-list-item-secondary"]');
            const usdEl = item.locator('[data-testid="multichain-token-list-item-primary"]');

            const name = await nameEl.textContent().catch(() => '') || '';
            const balance = await balanceEl.textContent().catch(() => '') || '';
            const usd = await usdEl.textContent().catch(() => '') || '';

            if (name.trim()) {
              tokenBalances.push({
                name: name.trim(),
                balance: balance.trim(),
                usdValue: usd.trim(),
              });
            }
          } catch (e) {
            // Skip this token
          }
        }
      }
    } catch (e) {
      console.log('   (Could not retrieve token list)');
    }

    // Get current network
    let network = 'Unknown';
    try {
      const networkEl = page.locator('[data-testid="network-display"]');
      if (await networkEl.isVisible({ timeout: 3000 })) {
        network = await networkEl.textContent() || 'Unknown';
        network = network.trim();
      }
    } catch (e) {
      // ignore
    }

    // Display results
    console.log('\n' + '═'.repeat(50));
    console.log('💼 AGENT WALLET BALANCE');
    console.log('═'.repeat(50));
    console.log(`🌐 Network:  ${network}`);
    console.log(`📬 Address:  ${address}`);
    console.log('─'.repeat(50));
    console.log(`⟠  ETH:      ${ethBalance}`);
    if (ethUsdValue && ethUsdValue !== 'Unknown') {
      console.log(`   USD:      ${ethUsdValue}`);
    }

    if (tokenBalances.length > 0) {
      console.log('─'.repeat(50));
      console.log('🪙 TOKENS:');
      for (const token of tokenBalances) {
        console.log(`   ${token.name.padEnd(10)} ${token.balance}`);
        if (token.usdValue) {
