// src/guard.ts - Permission check
import { readFileSync } from 'fs';
import { TransactionIntent, GuardResult } from './types';
import { getUSDPrice } from './price';

export async function checkPermissions(intent: TransactionIntent): Promise<GuardResult> {
  const permissions = JSON.parse(
    readFileSync('./permissions.json', 'utf-8')
  );

  // Check if revoked
  if (permissions.revoked) {
    return { allowed: false, reason: 'Agent wallet has been revoked' };
  }

  // Estimate USD value
  const usdValue = await getUSDPrice(intent);

  // Check per-tx limit
  const perTxLimit = BigInt(permissions.constraints.spendLimit.perTx);
  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      reason: `$${usdValue / 1_000_000n} exceeds per-tx limit of $${perTxLimit / 1_000_000n}`
    };
  }

  // Check daily limit
  const dailySpent = await getDailySpent();
  const dailyLimit = BigInt(permissions.constraints.spendLimit.daily);
  if (dailySpent + usdValue > dailyLimit) {
    return {
      allowed: false,
      reason: `Would exceed daily limit. Spent: $${dailySpent / 1_000_000n}, Limit: $${dailyLimit / 1_000_000n}`
    };
  }

  // Check if approval required
  const approvalThreshold = BigInt(permissions.constraints.requireApproval?.above ?? '0');
  if (approvalThreshold > 0n && usdValue >= approvalThreshold) {
    return {
      allowed: false,
      requiresApproval: true,
      reason: `Transaction value $${usdValue / 1_000_000n} requires explicit approval`
    };
  }

  return { allowed: true, estimatedUSD: usdValue };
}
```

