  await page.click('[data-testid="swap-button"]');
  await page.click('[data-testid="confirm-swap-button"]');

  // Handle MetaMask popup
  const mmPage = await waitForMetaMaskPopup(browser);

  // Verify transaction details in MetaMask
  const txValue = await mmPage.textContent('.transaction-detail-value');
  const txTo    = await mmPage.textContent('.transaction-detail-to');

  console.log(`MetaMask showing: ${txValue} ETH to ${txTo}`);

  // Final guard check before confirming
  const finalCheck = await checkPermissions({
    to: route.tx.to,
    value: route.tx.value,
    data: route.tx.data,
  });

  if (!finalCheck.allowed) {
    await mmPage.click('[data-testid="page-container-footer-cancel"]');
    throw new Error(`Guard blocked: ${finalCheck.reason}`);
  }

  // Confirm in MetaMask
  await mmPage.click('[data-testid="page-container-footer-next"]');

  // Wait for tx hash
  const txHash = await waitForTransactionHash(page);
  return txHash;
}
