## Step 1: Check Permissions & Balance

First, let me verify the constraints allow this swap.

```typescript
// src/guard.ts - Permission check
import { readFileSync } from 'fs';
import { ethers } from 'ethers';
import { getEthPrice } from './price';

interface Permissions {
  constraints: {
    spendLimit: {
      daily: string;
      perTx: string;
    };
    allowedChains: number[];
    allowedProtocols: string[];
    blockedMethods: string[];
    requireApproval: {
      above: string;
    };
    revoked: boolean;
  };
}

interface GuardResult {
  allowed: boolean;
  requiresApproval: boolean;
  reason?: string;
}

export async function checkPermissions(
  txIntent: {
    to: string;
    value: string;
    data: string;
    chainId: number;
    estimatedUsdValue: string;
  }
): Promise<GuardResult> {
  const permissions: Permissions = JSON.parse(
    readFileSync('./permissions.json', 'utf-8')
  );
  const { constraints } = permissions;

  // 1. Check if revoked
  if (constraints.revoked) {
    return { allowed: false, requiresApproval: false, reason: 'Agent wallet is revoked' };
  }

  // 2. Check chain allowlist
  if (!constraints.allowedChains.includes(txIntent.chainId)) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Chain ${txIntent.chainId} not in allowlist: ${constraints.allowedChains.join(', ')}`
    };
  }

  // 3. Check protocol allowlist
  const toAddressLower = txIntent.to.toLowerCase();
  const isAllowedProtocol = constraints.allowedProtocols
    .map(p => p.toLowerCase())
    .includes(toAddressLower);

  if (!isAllowedProtocol) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Contract ${txIntent.to} not in protocol allowlist`
    };
  }

  // 4. Check blocked methods (first 4 bytes of calldata)
  const methodSelector = txIntent.data.slice(0, 10);
  if (constraints.blockedMethods.includes(methodSelector)) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Method ${methodSelector} is blocked`
    };
  }

  // 5. Check per-tx spend limit
  const usdValue = BigInt(txIntent.estimatedUsdValue);
  const perTxLimit = BigInt(constraints.spendLimit.perTx);
  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Tx value $${Number(usdValue) / 1e6} exceeds per-tx limit $${Number(perTxLimit) / 1e6}`
    };
  }

  // 6. Check daily spend limit (load from log)
  const dailySpent = await getDailySpent();
  const dailyLimit = BigInt(constraints.spendLimit.daily);
  if (dailySpent + usdValue > dailyLimit) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Would exceed daily limit. Spent: $${Number(dailySpent) / 1e6}, Limit: $${Number(dailyLimit) / 1e6}`
    };
  }

  // 7. Check if approval required
  const approvalThreshold = BigInt(constraints.requireApproval.above);
  if (usdValue > approvalThreshold) {
    return {
      allowed: true,
      requiresApproval: true,
      reason: `Value $${Number(usdValue) / 1e6} exceeds approval threshold $${Number(approvalThreshold) / 1e6}`
    };
  }

  return { allowed: true, requiresApproval: false };
}

async function getDailySpent(): Promise<bigint> {
  // Read from transaction log, sum last 24h
  try {
    const logs = JSON.parse(readFileSync('~/.agent-wallet/logs/txs.json', 'utf-8'));
    const oneDayAgo = Date.now() - 86_400_000;
    return logs
      .filter((l: any) => l.timestamp > oneDayAgo && l.outcome === 'confirmed')
      .reduce((sum: bigint, l: any) => sum + BigInt(l.usdValue ?? '0'), 0n);
  } catch {
    return 0n;
  }
}
```

