// src/guard.ts
import { Permissions, TransactionIntent, GuardResult } from './types';
import { getDailySpend, recordSpend } from './logger';

// USDC on Ethereum mainnet
const USDC_ADDRESS = '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48';

export async function checkTransaction(
  intent: TransactionIntent,
  permissions: Permissions
): Promise<GuardResult> {

  // 0. Revocation check
  if (permissions.revoked) {
    return { allowed: false, requiresApproval: false, reason: 'Wallet access revoked' };
  }

  // 1. Chain allowlist
  if (!permissions.constraints.allowedChains.includes(intent.chainId)) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Chain ${intent.chainId} not in allowlist: [${permissions.constraints.allowedChains}]`
    };
  }

  // 2. Protocol allowlist (for contract calls; skip for plain transfers)
  const isContractCall = intent.data !== '0x' && intent.data.length > 2;
  if (isContractCall) {
    const toNorm = intent.to.toLowerCase();
    const allowed = permissions.constraints.allowedProtocols
      .map(p => p.toLowerCase())
      .includes(toNorm);
    if (!allowed) {
      return {
        allowed: false,
        requiresApproval: false,
        reason: `Protocol ${intent.to} not in allowlist`
      };
    }

    // 3. Blocked method selectors
    const selector = intent.data.slice(0, 10); // 0x + 4 bytes
    if (permissions.constraints.blockedMethods.includes(selector)) {
      return {
        allowed: false,
        requiresApproval: false,
        reason: `Method selector ${selector} is blocked`
      };
    }
  }

  const usdValue = BigInt(intent.estimatedUsdValue);

  // 4. Per-transaction spend limit
  const perTxLimit = BigInt(permissions.constraints.spendLimit.perTx);
  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Transaction value $${formatUsd(usdValue)} exceeds per-tx limit $${formatUsd(perTxLimit)}`
    };
  }

  // 5. Daily spend limit
  const dailySpent = await getDailySpend();
  const dailyLimit = BigInt(permissions.constraints.spendLimit.daily);
  if (dailySpent + usdValue > dailyLimit) {
    return {
      allowed: false,
      requiresApproval: false,
      reason: `Would exceed daily limit. Spent: $${formatUsd(dailySpent)}, Limit: $${formatUsd(dailyLimit)}`
    };
  }

  // 6. Approval threshold
  const approvalThreshold = BigInt(permissions.constraints.requireApproval.above);
  if (usdValue > approvalThreshold) {
    return {
      allowed: true,
      requiresApproval: true,
      reason: `Value $${formatUsd(usdValue)} exceeds approval threshold $${formatUsd(approvalThreshold)}`
    };
  }

  return { allowed: true, requiresApproval: false };
}

function formatUsd(val: bigint): string {
  return (Number(val) / 1_000_000).toFixed(2);
}
