// ============================================================
// MetaMask Agent Wallet Skill
// Swap 500 USDC → WETH via 0x Protocol
// Target contract: 0x4E15361FD6b4BB609Fa63C81A2be19d873717870
// ============================================================

import { chromium, BrowserContext, Page } from "playwright";
import * as fs from "fs";
import * as path from "path";

// ─── Types ───────────────────────────────────────────────────

interface Permissions {
  revoked?: boolean;
  constraints: {
    spendLimit: { daily: string; perTx: string };
    allowedChains: number[];
    allowedProtocols: string[];
    blockedMethods?: string[];
    requireApproval?: { above: string };
  };
}

interface TransactionIntent {
  to: string;
  value: string;
  data: string;
  chainId: number;
  estimatedUsdValue: string;
}

interface GuardResult {
  allowed: boolean;
  reason?: string;
  requiresApproval?: boolean;
}

interface LogEntry {
  timestamp: number;
  action: string;
  intent: TransactionIntent;
  guardResult: GuardResult;
  outcome: "confirmed" | "rejected" | "pending_approval" | "error";
  txHash?: string;
  error?: string;
}

// ─── Configuration ───────────────────────────────────────────

const PROFILE_DIR = path.join(
  process.env.HOME || "~",
  ".agent-wallet",
  "chrome-profile"
);
const LOG_DIR = path.join(
  process.env.HOME || "~",
  ".agent-wallet",
  "logs"
);
const PERMISSIONS_PATH = path.join(__dirname, "permissions.json");

// MetaMask extension ID (stable for MV3 release)
const MM_EXTENSION_ID = "nkbihfbeogaeaoehlefnkodbefgpgknn";

// USDC on Ethereum mainnet
const USDC_ADDRESS = "0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48";
const WETH_ADDRESS = "0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2";

// Target swap contract (0x Exchange Proxy)
const SWAP_CONTRACT = "0x4E15361FD6b4BB609Fa63C81A2be19d873717870";

// USDC has 6 decimals
const USDC_AMOUNT = 500n * 10n ** 6n; // 500 USDC

// ─── Permissions Guard ───────────────────────────────────────

function loadPermissions(): Permissions {
  if (!fs.existsSync(PERMISSIONS_PATH)) {
    // Default permissive config for demo — tighten in production
    return {
      constraints: {
        spendLimit: {
          daily: "1000000000",  // $1000
          perTx:  "600000000",  // $600 (covers 500 USDC + slippage)
        },
        allowedChains: [1],
        allowedProtocols: [
          SWAP_CONTRACT.toLowerCase(),
          USDC_ADDRESS.toLowerCase(),
        ],
        requireApproval: { above: "1000000000" }, // require approval above $1000
      },
    };
  }
  return JSON.parse(fs.readFileSync(PERMISSIONS_PATH, "utf-8"));
}

function checkGuard(
  intent: TransactionIntent,
  permissions: Permissions
): GuardResult {
  const { constraints } = permissions;

  // Hard kill-switch
  if (permissions.revoked) {
    return { allowed: false, reason: "Wallet permissions revoked" };
  }

  // Chain check
  if (!constraints.allowedChains.includes(intent.chainId)) {
    return {
      allowed: false,
      reason: `Chain ${intent.chainId} not in allowlist: [${constraints.allowedChains}]`,
    };
  }

  // Protocol check
  const toNorm = intent.to.toLowerCase();
  if (!constraints.allowedProtocols.includes(toNorm)) {
    return {
      allowed: false,
      reason: `Contract ${intent.to} not in protocol allowlist`,
    };
  }

  // Per-tx spend limit (USD, 6-decimal representation)
  const usdValue = BigInt(intent.estimatedUsdValue);
  const perTxLimit = BigInt(constraints.spendLimit.perTx);
  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      reason: `Transaction value $${
        Number(usdValue) / 1e6
      } exceeds per-tx limit $${Number(perTxLimit) / 1e6}`,
    };
  }

  // Approval threshold
  if (constraints.requireApproval) {
    const approvalThreshold = BigInt(constraints.requireApproval.above);
    if (usdValue > approvalThreshold) {
      return {
        allowed: true,
        requiresApproval: true,
      };
    }
  }

  return { allowed: true };
}

// ─── Logger ──────────────────────────────────────────────────

function writeLog(entry: LogEntry): void {
  if (!fs.existsSync(LOG_DIR)) fs.mkdirSync(LOG_DIR, { recursive: true });
  const file = path.join(
    LOG_DIR,
    `${new Date().toISOString().slice(0, 10)}.jsonl`
  );
  fs.appendFileSync(file, JSON.stringify(entry) + "\n");
  console.log("[LOG]", JSON.stringify(entry, null, 2));
}

// ─── Browser / MetaMask Helpers ──────────────────────────────

async function launchBrowserWithMetaMask(): Promise<{
  context: BrowserContext;
  mmPage: Page;
}> {
  console.log("[Browser] Launching Chromium with MetaMask extension…");

  const extensionPath = path.join(
    __dirname,
    "extensions",
    "metamask"
  );

  const context = await chromium.launchPersistentContext(PROFILE_DIR, {
    headless: false, // MetaMask requires headed mode
    args: [
      `--disable-extensions-except=${extensionPath}`,
      `--load-extension=${extensionPath}`,
      "--no-sandbox",
      "--disable-setuid-sandbox",
    ],
    viewport: { width: 1280, height: 800 },
  });

  // Wait for MetaMask service worker / background page
  let mmPage: Page | undefined;
  for (let i = 0; i < 10; i++) {
    const pages = context.pages();
    mmPage = pages.find((p) =>
      p.url().includes(MM_EXTENSION_ID)
    );
    if (mmPage) break;
    await new Promise((r) => setTimeout(r, 1000));
  }

  if (!mmPage) {
    // Open MetaMask popup manually
    mmPage = await context.newPage();
    await mmPage.goto(
      `chrome-extension://${MM_EXTENSION_ID}/home.html`
    );
  }

  console.log("[Browser] MetaMask page found:", mmPage.url());
  return { context, mmPage };
}

