interface GuardResult {
  allowed: boolean;
  reason?: string;
  requiresApproval: boolean;
}

async function checkTransaction(tx: TransactionIntent): Promise<GuardResult> {
  const usdValue = 1_000_000_000; // $1000 in 6-decimal USDC units

  // Check 1: Per-transaction limit
  if (usdValue > permissions.constraints.spendLimit.perTx) {
    return { allowed: false, reason: 'Exceeds per-tx spend limit', requiresApproval: false };
  }

  // Check 2: Daily limit (rolling 24h)
  const dailySpent = await getDailySpent(); // reads from logs
  if (dailySpent + usdValue > permissions.constraints.spendLimit.daily) {
    return { allowed: false, reason: 'Exceeds daily spend limit', requiresApproval: false };
  }

  // Check 3: Protocol allowlist
  if (!permissions.constraints.allowedProtocols.includes(tx.to.toLowerCase())) {
    return { allowed: false, reason: `Protocol ${tx.to} not in allowlist`, requiresApproval: false };
  }

  // Check 4: Chain
  if (!permissions.constraints.allowedChains.includes(tx.chainId)) {
    return { allowed: false, reason: `Chain ${tx.chainId} not allowed`, requiresApproval: false };
  }

  // Check 5: Approval threshold
  const requiresApproval = usdValue > permissions.constraints.requireApproval.above;

  return { allowed: true, requiresApproval };
}
