// src/config.ts
import { readFileSync } from 'fs';
import { homedir } from 'os';
import { join } from 'path';

export interface Permissions {
  constraints: {
    spendLimit: {
      daily: string;   // in token's smallest unit (6 decimals for USDC)
      perTx: string;
    };
    allowedChains: number[];
    allowedProtocols: string[];
    blockedMethods: string[];
    requireApproval: {
      above: string;
    };
  };
  revoked?: boolean;
}

export function loadPermissions(): Permissions {
  const path = join(homedir(), '.agent-wallet', 'permissions.json');
  return JSON.parse(readFileSync(path, 'utf-8'));
}
```

```typescript
// src/guard.ts
import { loadPermissions } from './config';
import { getUSDPrice } from './price';
import { TransactionIntent } from './types';

const ARBITRUM_CHAIN_ID = 42161;
const UNISWAP_V3_ROUTER_ARBITRUM = '0xE592427A0AEce92De3Edee1F18E0157C05861564';
const USDC_E_ARBITRUM = '0xFF970A61A04b1cA14834A43f5dE4533eBDDB5CC8';

export async function checkPermissions(intent: TransactionIntent): Promise<{
  allowed: boolean;
  reason?: string;
  requiresApproval?: boolean;
}> {
  const perms = loadPermissions();

  // Hard stop if revoked
  if (perms.revoked) {
    return { allowed: false, reason: 'Agent wallet is revoked' };
  }

  // Chain check
  if (!perms.constraints.allowedChains.includes(intent.chainId)) {
    return {
      allowed: false,
      reason: `Chain ${intent.chainId} not in allowlist: ${perms.constraints.allowedChains}`
    };
  }

  // Protocol check
  const toAddr = intent.to.toLowerCase();
  const allowed = perms.constraints.allowedProtocols
    .map(a => a.toLowerCase())
    .includes(toAddr);

  if (!allowed) {
    return {
      allowed: false,
      reason: `Contract ${intent.to} not in protocol allowlist`
    };
  }

  // Method selector check (first 4 bytes of calldata)
  if (intent.data && intent.data.length >= 10) {
    const selector = intent.data.slice(0, 10);
    if (perms.constraints.blockedMethods.includes(selector)) {
      return {
        allowed: false,
        reason: `Method selector ${selector} is blocked`
      };
    }
  }

  // USD value check
  const usdValue = await getUSDPrice(intent.tokenIn, intent.amountIn);
  const perTxLimit = BigInt(perms.constraints.spendLimit.perTx);

  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      reason: `Transaction value $${usdValue / 1_000_000n} exceeds per-tx limit $${perTxLimit / 1_000_000n}`
    };
  }

  // Approval threshold check
  const approvalThreshold = BigInt(perms.constraints.requireApproval.above);
  if (usdValue > approvalThreshold) {
    return { allowed: true, requiresApproval: true };
  }

  return { allowed: true };
}
