// src/guard.ts
import { AgentConfig, TransactionIntent, GuardResult } from './types';
import { getSpentToday } from './logger';

export async function checkGuard(
  intent: TransactionIntent,
  config: AgentConfig
): Promise<GuardResult> {
  const { constraints } = config;

  // ── 1. Global kill switch ──────────────────────────────────────────────
  if (config.revoked) {
    return { allowed: false, reason: 'Agent wallet has been revoked.' };
  }

  // ── 2. Chain allowlist ─────────────────────────────────────────────────
  if (!constraints.allowedChains.includes(intent.chainId)) {
    return {
      allowed: false,
      reason: `Chain ${intent.chainId} is not in the allowlist: [${constraints.allowedChains}]`,
    };
  }

  // ── 3. Protocol allowlist ──────────────────────────────────────────────
  const toNorm = intent.to.toLowerCase();
  const allowed = constraints.allowedProtocols.map(a => a.toLowerCase());

  if (!allowed.includes(toNorm)) {
    return {
      allowed: false,
      reason:
        `Contract ${intent.to} is NOT in the allowed-protocols list.\n` +
        `Allowed: ${constraints.allowedProtocols.join(', ') || '(none)'}`,
    };
  }

  // ── 4. Blocked method selectors ────────────────────────────────────────
  if (constraints.blockedMethods?.length) {
    const selector = intent.data.slice(0, 10).toLowerCase(); // 0x + 4 bytes
    if (constraints.blockedMethods.map(m => m.toLowerCase()).includes(selector)) {
      return {
        allowed: false,
        reason: `Method selector ${selector} is explicitly blocked.`,
      };
    }
  }

  // ── 5. Per-transaction spend limit ────────────────────────────────────
  const usdValue = BigInt(intent.estimatedUsdValue);
  const perTxLimit = BigInt(constraints.spendLimit.perTx);

  if (usdValue > perTxLimit) {
    return {
      allowed: false,
      reason:
        `Transaction value $${formatUsd(usdValue)} exceeds per-tx limit ` +
        `$${formatUsd(perTxLimit)}.`,
    };
  }

  // ── 6. Daily spend limit ──────────────────────────────────────────────
  const spentToday = await getSpentToday();
  const dailyLimit = BigInt(constraints.spendLimit.daily);

  if (spentToday + usdValue > dailyLimit) {
    return {
      allowed: false,
      reason:
        `Daily limit would be exceeded. ` +
        `Spent today: $${formatUsd(spentToday)}, ` +
        `this tx: $${formatUsd(usdValue)}, ` +
        `limit: $${formatUsd(dailyLimit)}.`,
    };
  }

  // ── 7. Approval threshold ─────────────────────────────────────────────
  if (constraints.requireApproval) {
    const threshold = BigInt(constraints.requireApproval.above);
    if (usdValue > threshold) {
      return {
        allowed: true,
        requiresApproval: true,
      };
    }
  }

  return { allowed: true };
}

function formatUsd(val: bigint): string {
  // 6-decimal USDC-style formatting
  const dollars = val / 1_000_000n;
  const cents = (val % 1_000_000n) / 10_000n;
  return `${dollars}.${String(cents).padStart(2, '0')}`;
}
```

